```class Solution {
public:
    string arrangeWords(string text) {
        vector<pair<int, string>> words;
        int n = text.size();
        text[0] = tolower(text[0]);
        for (int i = 1; i < n; i++) {
            if (text[i] == ' ') {
                words.push_back({(int)text.substr(0, i).size(), text.substr(0, i)});
                text = text.substr(i);
                i = 0;
            }
        }
        words.push_back({(int)text.size(), text});
        sort(words.begin(), words.end());
        string res;
        res += tolower(words[0].second[0]);
        for (int i = 1; i < words.size(); i++) {
            res += ' ' + words[i].second;
        }
        return res;
    }
};```
